const CUTOFF_HOURS = 30;
const now = Date.now();
const cutoff = now - CUTOFF_HOURS * 3600 * 1000;

function decodeEntities(str) {
  return (str || '')
    .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&apos;/g, "'")
    .replace(/&#x([0-9a-fA-F]+);/g, (m, h) => String.fromCodePoint(parseInt(h, 16)))
    .replace(/&#(\d+);/g, (m, d) => String.fromCodePoint(parseInt(d, 10)))
    .trim();
}

function stripHtml(str) {
  return (str || '')
    .replace(/<[^>]*>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function summarize(str, maxLen) {
  const clean = stripHtml(decodeEntities(str || ''));
  if (!clean) return '';
  if (clean.length <= maxLen) return clean;
  const cut = clean.slice(0, maxLen);
  const lastSpace = cut.lastIndexOf(' ');
  return (lastSpace > 0 ? cut.slice(0, lastSpace) : cut) + '…';
}

function parseFeed(xml) {
  const items = [];
  const isAtom = /<feed[\s>]/i.test(xml) && !/<rss[\s>]/i.test(xml);
  const blockRegex = isAtom ? /<entry[\s>][\s\S]*?<\/entry>/g : /<item[\s>][\s\S]*?<\/item>/g;
  const blocks = xml.match(blockRegex) || [];
  for (const block of blocks) {
    const titleMatch = block.match(/<title[^>]*>([\s\S]*?)<\/title>/);
    let link = null;
    if (isAtom) {
      const linkMatches = [...block.matchAll(/<link[^>]*href="([^"]+)"[^>]*\/?>/g)];
      const alt = linkMatches.find(m => /rel="alternate"/.test(m[0])) || linkMatches[0];
      link = alt ? alt[1] : null;
    } else {
      const linkMatch = block.match(/<link[^>]*>([\s\S]*?)<\/link>/);
      link = linkMatch ? linkMatch[1] : null;
    }
    const dateMatch = block.match(/<(?:pubDate|published|updated)>([\s\S]*?)<\/(?:pubDate|published|updated)>/);
    const descMatch = block.match(/<content:encoded[^>]*>([\s\S]*?)<\/content:encoded>/)
      || block.match(/<description[^>]*>([\s\S]*?)<\/description>/)
      || block.match(/<summary[^>]*>([\s\S]*?)<\/summary>/)
      || block.match(/<content[^>]*>([\s\S]*?)<\/content>/);
    const title = titleMatch ? decodeEntities(titleMatch[1]) : null;
    const dateStr = dateMatch ? decodeEntities(dateMatch[1]) : null;
    const ts = dateStr ? Date.parse(dateStr) : NaN;
    const desc = descMatch ? summarize(descMatch[1], 150) : '';
    if (title && link) {
      items.push({ title, link: decodeEntities(link), ts: isNaN(ts) ? null : ts, desc });
    }
  }
  return items;
}

